class InvoicePrinter {
  printLocation(invoice: Invoice) {
    const code = invoice.order.customer.address.postalCode;
    console.log(`Ship to: ${code}`);
  }
}

function notifyShipping(order: Order) {
  const city = order.customer.address.city;
  emailService.send(`Shipping to ${city}`);
}

// Version A: callers traverse into nested objects
function estimateTaxA(order: Order) {
  const region = order.customer.address.regionCode;
  return taxService.rateFor(region) * order.amount;
}

// Version B: Order provides a focused accessor
class Order {
  getDestinationRegion() { return this.customer.address.regionCode; }
}
function estimateTaxB(order: Order) {
  const region = order.getDestinationRegion();
  return taxService.rateFor(region) * order.amount;
}
